import json
b = json.load(open('baseline-packages.json'))
a = json.load(open('after-cpm-packages.json'))
# Compare resolved versions
def get_versions(data):
    result = {}
    for p in data.get('projects', []):
        name = p['path'].split('/')[-1]
        for fw in p.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result
bv = get_versions(b)
av = get_versions(a)
if bv == av:
    print('✓ All resolved package versions match between baseline and post-CPM.')
else:
    for k in set(list(bv.keys()) + list(av.keys())):
        if bv.get(k) != av.get(k):
            print(f'DIFF: {k}: {bv.get(k)} -> {av.get(k)}')
" 2>&1

